// -------------------------------------------------------
// Set START_DATE to when you got your Oura ring.
// END_DATE is today automatically.
// -------------------------------------------------------
const START_DATE = '2026-01-06'; // <-- CHANGE THIS

const today = new Date().toISOString().slice(0, 10);

return [{
  start_date: START_DATE,
  end_date: today
}];

const START_DATE = '2026-01-07'; // zmień na swoją datę
const today = new Date().toISOString().slice(0, 10);

const chunks = [];
let cursor = new Date(START_DATE);
const end = new Date(today);

while (cursor < end) {
  const chunkEnd = new Date(cursor);
  chunkEnd.setDate(chunkEnd.getDate() + 29);

  chunks.push({
    start_date: cursor.toISOString().slice(0, 10),
    end_date: (chunkEnd > end ? end : chunkEnd).toISOString().slice(0, 10)
  });

  cursor.setDate(cursor.getDate() + 30);
}

return chunks;

